<span class="line"><span style="color:#FFCB6B;">│</span><span style="color:#BABED8;">     </span><span style="color:#C3E88D;">└─index.vue</span><span style="color:#BABED8;">  </span><span style="color:#C3E88D;">index页面</span></span>
